OptimizationTimeBreakdown$RestDuration' => '<p>Resting phase of the cycle.</p> <p> <b>Unit</b>: <code>seconds</code> </p>', 'WaypointOptimizationTimeBreakdown$ServiceDuration' => '<p>Service time spent at the destination. At an appointment, the service time should be the appointment duration.</p> <p> <b>Unit</b>: <code>seconds</code> </p>', 'WaypointOptimizationTimeBreakdown$TravelDuration' => '<p>Traveling phase of the cycle.</p> <p> <b>Unit</b>: <code>seconds</code> </p>', 'WaypointOptimizationTimeBreakdown$WaitDuration' => '<p>Waiting phase of the cycle.</p> <p> <b>Unit</b>: <code>seconds</code> </p>', 'WaypointOptimizationWaypoint$ServiceDuration' => '<p>Service time spent at the waypoint. At an appointment, the service time should be the appointment duration.</p> <p> <b>Unit</b>: <code>seconds</code> </p>', ], ], 'GeometryFormat' => [ 'base' => NULL, 'refs' => [ 'CalculateIsolinesRequest$IsolineGeometryFormat' => '<p>The format of the returned IsolineGeometry. </p> <p>Default value:<code>FlexiblePolyline</code> </p>', 'CalculateIsolinesResponse$IsolineGeometryFormat' => '<p>The format of the returned geometries, matching the format specified in the request. Either <code> FlexiblePolyline</code> for compact encoding or <code>Simple</code> for GeoJSON-compatible coordinates.</p> <p>Default value:<code>FlexiblePolyline</code> </p>', 'CalculateRoutesRequest$LegGeometryFormat' => '<p>Specifies the format of the geometry returned for each leg of the route. You can choose between two different geometry encoding formats.</p> <p> <code>FlexiblePolyline</code>: A compact and precise encoding format for the leg geometry. For more information on the format, see the GitHub repository for <a href="https://github.com/aws-geospatial/polyline">https://github.com/aws-geospatial/polyline</a>.</p> <p> <code>Simple</code>: A less compact encoding, which is easier to decode but may be less precise and result in larger payloads.</p>', 'CalculateRoutesResponse$LegGeometryFormat' => '<p>Specifies the format of the geometry returned for each leg of the route.</p>', 'SnapToRoadsRequest$SnappedGeometryFormat' => '<p>Chooses what the returned SnappedGeometry format should be.</p> <p>Default value: <code>FlexiblePolyline</code> </p>', 'SnapToRoadsResponse$SnappedGeometryFormat' => '<p>Specifies the format of the geometry returned for each leg of the route.</p>', ], ], 'Heading' => [ 'base' => NULL, 'refs' => [ 'IsolineDestinationOptions$Heading' => '<p>The initial direction of travel in degrees (0-360, where 0 is north). This can affect which road segments are considered accessible from the starting point.</p>', 'IsolineOriginOptions$Heading' => '<p>Initial direction of travel in degrees (0-360, where 0 is north). This affects which road segments are considered accessible from the starting point and is particularly useful when the origin is on a divided road or at a complex intersection.</p>', 'RoadSnapTracePoint$Heading' => '<p>GPS Heading at the position.</p>', 'RouteDestinationOptions$Heading' => '<p>GPS Heading at the position.</p>', 'RouteMatrixDestinationOptions$Heading' => '<p>GPS Heading at the position.</p>', 'RouteMatrixOriginOptions$Heading' => '<p>GPS Heading at the position.</p>', 'RouteOriginOptions$Heading' => '<p>GPS Heading at the position.</p>', 'RouteWaypoint$Heading' => '<p> GPS Heading at the position. Not supported in <code>ap-southeast-1</code> and <code>ap-southeast-5</code> regions for <a href="https://docs.aws.amazon.com/location/latest/developerguide/GrabMaps.html">GrabMaps</a> customers. </p>', 'WaypointOptimizationDestinationOptions$Heading' => '<p>GPS Heading at the position.</p>', 'WaypointOptimizationWaypoint$Heading' => '<p>GPS Heading at the position.</p>', ], ], 'IndexList' => [ 'base' => NULL, 'refs' => [ 'RoutePedestrianSpan$Incidents' => '<p>Incidents corresponding to the span. These index into the Incidents in the parent Leg.</p>', 'RouteToll$Systems' => '<p>Toll systems are authorities that collect payments for the toll.</p>', 'RouteVehicleSpan$Incidents' => '<p>Incidents corresponding to the span. These index into the Incidents in the parent Leg.</p>', 'RouteVehicleSpan$Notices' => '<p>Notices are additional information returned that indicate issues that occurred during route calculation.</p>', 'RouteVehicleSpan$TollSystems' => '<p>Toll systems are authorities that collect payments for the toll.</p>', 'RouteVehicleSpan$TruckRoadTypes' => '<p>Truck road type identifiers. <code>BK1</code> through <code>BK4</code> apply only to Sweden. <code>A2,A4,B2,B4,C,D,ET2,ET4</code> apply only to Mexico.</p> <note> <p>There are currently no other supported values as of 26th April 2024.</p> </note>', 'RouteVehicleSpan$Zones' => '<p>Zones corresponding to this leg of the route.</p>', ], ], 'Integer' => [ 'base' => NULL, 'refs' => [ 'Corridor$Radius' => '<p>Radius that defines the width of the corridor.</p>', 'IndexList$member' => NULL, 'PolylineCorridor$Radius' => '<p>Considers all roads within the provided radius to match the provided destination to. The roads that are considered are determined by the provided Strategy.</p> <p> <b>Unit</b>: <code>meters</code> </p>', 'RoadSnapTracePointIndexList$member' => NULL, ], ], 'InternalServerException' => [ 'base' => '<p>The request processing has failed because of an unknown error, exception or failure.</p>', 'refs' => [], ], 'Isoline' => [ 'base' => '<p>Represents a single reachable area calculated for a specific threshold.</p>', 'refs' => [ 'IsolineList$member' => NULL, ], ], 'IsolineAllowOptions' => [ 'base' => '<p>Special road types or features that should be considered available for routing. For example, this attribute can be used to allow the use of HOV (high-occupancy vehicle) or HOT (high-occupancy toll) lanes, even if they would otherwise not be.</p>', 'refs' => [ 'CalculateIsolinesRequest$Allow' => '<p>Enables special road types or features that should be considered for routing even if they might be restricted by default for the selected travel mode. These include high-occupancy vehicle and toll lanes.</p>', ], ], 'IsolineAvoidanceArea' => [ 'base' => '<p>Defines an area to avoid when calculating routes. Consists of a primary geometry to avoid, with the ability to specify exception areas within that geometry where travel is permitted.</p>', 'refs' => [ 'IsolineAvoidanceAreaList$member' => NULL, ], ], 'IsolineAvoidanceAreaGeometry' => [ 'base' => '<p>Defines an area to avoid during calculations using one of several supported geometry types. The service will prefer routes that avoid these areas when possible.</p>', 'refs' => [ 'IsolineAvoidanceArea$Geometry' => '<p>The primary area to avoid, specified using a bounding box, corridor, polygon, or polyline corridor.</p>', 'IsolineAvoidanceAreaGeometryList$member' => NULL, ], ], 'IsolineAvoidanceAreaGeometryList' => [ 'base' => NULL, 'refs' => [ 'IsolineAvoidanceArea$Except' => '<p>Areas within the primary avoidance geometry where travel is allowed. For example, you might want to avoid a neighborhood but allow travel on a major road that passes through it.</p>', ], ], 'IsolineAvoidanceAreaGeometryPolygonList' => [ 'base' => NULL, 'refs' => [ 'IsolineAvoidanceAreaGeometry$Polygon' => '<p>A polygon defined by a list of coordinate rings. The first ring defines the outer boundary; subsequent rings will be ignored.</p>', ], ], 'IsolineAvoidanceAreaGeometryPolylinePolygonList' => [ 'base' => NULL, 'refs' => [ 'IsolineAvoidanceAreaGeometry$PolylinePolygon' => '<p>A polygon defined by encoded polyline strings. The first string defines the outer boundary; subsequent strings will be ignored. For more information on polyline encoding, see <a href="https://github.com/aws-geospatial/polyline">https://github.com/aws-geospatial/polyline</a>.</p>', ], ], 'IsolineAvoidanceAreaList' => [ 'base' => NULL, 'refs' => [ 'IsolineAvoidanceOptions$Areas' => '<p>Specifies geographic areas to avoid where possible. Routes may still pass through these areas if no reasonable alternative exists.</p>', ], ], 'IsolineAvoidanceOptions' => [ 'base' => '<p>Specifies features of the road network to avoid when calculating reachable areas. These preferences guide route calculations but may be overridden when no reasonable alternative exists. For example, if avoiding toll roads would make an area unreachable, toll roads may still be used.</p> <p>Avoidance options include physical features (like ferries and tunnels), road characteristics (like dirt roads and highways), and regulated areas (like congestion zones). They can be combined to match specific routing needs, such as avoiding both toll roads and ferries.</p>', 'refs' => [ 'CalculateIsolinesRequest$Avoid' => '<p>Specifies road types, features, or areas to avoid (if possible) when calculating reachable areas. These are treated as preferences rather than strict constraints—if a route cannot be calculated without using an avoided feature, that avoidance preference may be ignored.</p>', ], ], 'IsolineAvoidanceZoneCategory' => [ 'base' => '<p>Types of regulated zones that may affect routing.</p>', 'refs' => [ 'IsolineAvoidanceZoneCategoryList$member' => NULL, ], ], 'IsolineAvoidanceZoneCategoryList' => [ 'base' => NULL, 'refs' => [ 'IsolineAvoidanceOptions$ZoneCategories' => '<p>Indicates types of regulated zones (such as congestion pricing or environmental zones) to avoid where possible. Routes may still pass through these zones if no reasonable alternative exists.</p>', ], ], 'IsolineCarOptions' => [ 'base' => '<p>Vehicle characteristics and preferences that affect routing for passenger cars. This includes vehicle type, occupancy, and speed restrictions that may influence which roads can be used and expected travel times.</p>', 'refs' => [ 'IsolineTravelModeOptions$Car' => '<p>Options specific to passenger vehicle routing (<code>Car</code>, such as vehicle characteristics and license plate restrictions.</p>', ], ], 'IsolineCarOptionsMaxSpeedDouble' => [ 'base' => NULL, 'refs' => [ 'IsolineCarOptions$MaxSpeed' => '<p>The maximum speed of the vehicle in kilometers per hour. When specified, routes will not include roads with higher speed limits. Valid values range from 3.6 km/h (1 m/s) to 252 km/h (70 m/s).</p> <p> <b>Unit</b>: <code>kilometers per hour</code> </p>', ], ], 'IsolineCarOptionsOccupancyInteger' => [ 'base' => NULL, 'refs' => [ 'IsolineCarOptions$Occupancy' => '<p>The number of occupants in the vehicle. This can affect route calculations by enabling the use of high-occupancy vehicle (HOV) lanes where minimum occupancy requirements are met.</p> <p>Default value: <code>1</code> </p>', ], ], 'IsolineConnection' => [ 'base' => '<p>Represents a segment of the transportation network that connects separate parts of a reachable area. These connections show how discontinuous areas are linked, such as by ferry routes or bridges crossing unroutable terrain.</p>', 'refs' => [ 'IsolineConnectionList$member' => NULL, ], ], 'IsolineConnectionFromPolygonIndexInteger' => [ 'base' => NULL, 'refs' => [ 'IsolineConnection$FromPolygonIndex' => '<p>The index of the starting polygon in the isoline\'s <code>Geometries</code> list.</p>', ], ], 'IsolineConnectionGeometry' => [ 'base' => '<p>Represents the geometry of connections between non-contiguous parts of an isoline. These connections can be provided in either coordinate pairs (LineString) or encoded (Polyline) format, matching the format specified in the request.</p>', 'refs' => [ 'IsolineConnection$Geometry' => '<p>The shape of the connection, representing the actual path through the transportation network that links the polygons.</p>', ], ], 'IsolineConnectionList' => [ 'base' => NULL, 'refs' => [ 'Isoline$Connections' => '<p>Lines connecting separate parts of the reachable area that can be reached within the same threshold. These occur when areas are reachable but not contiguous, such as when separated by water or unroutable areas. When present, these lines represent actual transportation network segments (such as ferry routes or bridges) that connect the separated areas.</p>', ], ], 'IsolineConnectionToPolygonIndexInteger' => [ 'base' => NULL, 'refs' => [ 'IsolineConnection$ToPolygonIndex' => '<p>The index of the ending polygon in the isoline\'s <code>Geometries</code> list.</p>', ], ], 'IsolineDestinationOptions' => [ 'base' => '<p>Options that control how the destination point is interpreted and matched to the road network when calculating reachable areas. This affects which roads are considered accessible near the destination and how the final approach is calculated.</p>', 'refs' => [ 'CalculateIsolinesRequest$DestinationOptions' => '<p>Options that control how the destination point is matched to the road network and how routes can approach it. These options help improve travel time accuracy by accounting for real-world access to the destination.</p>', ], ], 'IsolineEngineType' => [ 'base' => NULL, 'refs' => [ 'IsolineCarOptions$EngineType' => '<p>The type of engine powering the vehicle, which may affect route calculation due to road restrictions or vehicle characteristics.</p> <ul> <li> <p> <code>INTERNAL_COMBUSTION</code>—Standard gasoline or diesel engine.</p> </li> <li> <p> <code>ELECTRIC</code>—Battery electric vehicle.</p> </li> <li> <p> <code>PLUGIN_HYBRID</code>—Combination of electric and internal combustion engines with plug-in charging capability.</p> </li> </ul>', 'IsolineScooterOptions$EngineType' => '<p>The type of engine powering the vehicle, which may affect route calculation due to road restrictions or vehicle characteristics.</p> <ul> <li> <p> <code>INTERNAL_COMBUSTION</code>—Standard gasoline or diesel engine.</p> </li> <li> <p> <code>ELECTRIC</code>—Battery electric vehicle.</p> </li> <li> <p> <code>PLUGIN_HYBRID</code>—Combination of electric and internal combustion engines with plug-in charging capability.</p> </li> </ul>', 'IsolineTruckOptions$EngineType' => '<p>The type of engine powering the vehicle, which may affect route calculation due to road restrictions or vehicle characteristics.</p> <ul> <li> <p> <code>INTERNAL_COMBUSTION</code>—Standard gasoline or diesel engine.</p> </li> <li> <p> <code>ELECTRIC</code>—Battery electric vehicle.</p> </li> <li> <p> <code>PLUGIN_HYBRID</code>—Combination of electric and internal combustion engines with plug-in charging capability.</p> </li> </ul>', ], ], 'IsolineGranularityOptions' => [ 'base' => '<p>Controls the detail level and smoothness of generated isolines. More detailed isolines provide better visual representation of reachable areas but require more processing time and result in larger responses.</p>', 'refs' => [ 'CalculateIsolinesRequest$IsolineGranularity' => '<p>Controls the detail level of the generated isolines. Higher granularity produces smoother shapes but requires more processing time and results in larger responses.</p>', ], ], 'IsolineGranularityOptionsMaxPointsInteger' => [ 'base' => NULL, 'refs' => [ 'IsolineGranularityOptions$MaxPoints' => '<p>The maximum number of points used to define each isoline. Higher values create smoother, more detailed shapes.</p>', ], ], 'IsolineHazardousCargoType' => [ 'base' => NULL, 'refs' => [ 'IsolineHazardousCargoTypeList$member' => NULL, ], ], 'IsolineHazardousCargoTypeList' => [ 'base' => NULL, 'refs' => [ 'IsolineTruckOptions$HazardousCargos' => '<p>Types of hazardous materials being transported. This affects which roads and tunnels can be used based on local regulations.</p> <ul> <li> <p> <code>Combustible</code>—Materials that can burn readily</p> </li> <li> <p> <code>Corrosive</code>—Materials that can destroy or irreversibly damage other substances</p> </li> <li> <p> <code>Explosive</code>—Materials that can produce an explosion by chemical reaction</p> </li> <li> <p> <code>Flammable</code>—Materials that can easily ignite</p> </li> <li> <p> <code>Gas</code>—Hazardous materials in gaseous form</p> </li> <li> <p> <code>HarmfulToWater</code>—Materials that pose a risk to water sources if released</p> </li> <li> <p> <code>Organic</code>—Hazardous organic compounds</p> </li> <li> <p> <code>Other</code>—Hazardous materials not covered by other categories</p> </li> <li> <p> <code>Poison</code>—Toxic materials</p> </li> <li> <p> <code>PoisonousInhalation</code>—Materials that are toxic when inhaled</p> </li> <li> <p> <code>Radioactive</code>—Materials that emit ionizing radiation</p> </li> </ul>', ], ], 'IsolineList' => [ 'base' => NULL, 'refs' => [ 'CalculateIsolinesResponse$Isolines' => '<p>Reachable areas, or isolines, for each threshold specified in the request.</p>', ], ], 'IsolineMatchingOptions' => [ 'base' => '<p>Controls how origin and destination points are matched to the road network when they don\'t fall exactly on a road. Matching options help ensure realistic routing by connecting points to appropriate roads.</p>', 'refs' => [ 'IsolineDestinationOptions$Matching' => '<p>Controls how the destination point is matched to the road network, including search radius and name-based matching preferences.</p>', 'IsolineOriginOptions$Matching' => '<p>Controls how the origin point is matched to the road network, including search radius and matching strategy.</p>', ], ], 'IsolineOptimizationObjective' => [ 'base' => NULL, 'refs' => [ 'CalculateIsolinesRequest$OptimizeIsolineFor' => '<p>Controls the trade-off between calculation speed and isoline precision. Choose <code> FastCalculation</code> for quicker results with less detail, <code>AccurateCalculation</code> for more precise results, or <code>BalancedCalculation</code> for a middle ground.</p> <p>Default value: <code>BalancedCalculation</code> </p>', ], ], 'IsolineOriginOptions' => [ 'base' => '<p>Options that control how the origin point is interpreted when calculating reachable areas. These options affect which roads are considered accessible from the starting point and how initial routing decisions are made.</p>', 'refs' => [ 'CalculateIsolinesRequest$OriginOptions' => '<p>Options that control how the origin point is matched to the road network and how routes can depart from it. These options help improve travel time accuracy by accounting for real-world access from the origin.</p>', ], ], 'IsolineScooterOptions' => [ 'base' => '<p>Vehicle characteristics that affect which roads and paths can be used when calculating reachable areas for scooters. This includes areas such as bike lanes, shared paths, and roads where scooters are permitted.</p>', 'refs' => [ 'IsolineTravelModeOptions$Scooter' => '<p>Options specific to scooter routing (<code>Scooter</code>, such as vehicle characteristics and license plate restrictions.</p> <note> <p>When using the <code>Scooter</code> travel mode, controlled-access highways are automatically avoided unless explicitly allowed.</p> </note>', ], ], 'IsolineScooterOptionsMaxSpeedDouble' => [ 'base' => NULL, 'refs' => [ 'IsolineScooterOptions$MaxSpeed' => '<p>The maximum speed of the vehicle in kilometers per hour. When specified, routes will not include roads with higher speed limits. Valid values range from 3.6 km/h (1 m/s) to 252 km/h (70 m/s).</p> <p> <b>Unit</b>: <code>kilometers per hour</code> </p>', ], ], 'IsolineScooterOptionsOccupancyInteger' => [ 'base' => NULL, 'refs' => [ 'IsolineScooterOptions$Occupancy' => '<p>The number of occupants in the vehicle. This can affect route calculations by enabling the use of high-occupancy vehicle (HOV) lanes where minimum occupancy requirements are met.</p> <p>Default value: <code>1</code> </p>', ], ], 'IsolineShapeGeometry' => [ 'base' => '<p>Represents the shape of a reachable area. The geometry can be provided either as coordinate pairs (<code>Polygon</code>) or in encoded format (<code>PolylinePolygon</code>), matching the format specified in the request.</p>', 'refs' => [ 'IsolineShapeGeometryList$member' => NULL, ], ], 'IsolineShapeGeometryList' => [ 'base' => NULL, 'refs' => [ 'Isoline$Geometries' => '<p>The shapes that define the reachable area, provided in the requested geometry format.</p>', ], ], 'IsolineSideOfStreetOptions' => [ 'base' => '<p>Controls how points are matched to specific sides of streets. This is important when the side of the street matters for accessibility - for example, when building entrances or parking lot access points can only be reached from one side of a divided road.</p>', 'refs' => [ 'IsolineDestinationOptions$SideOfStreet' => '<p>Specifies which side of the street should be considered accessible, which is important when building entrances or parking access points are only reachable from one side of the road.</p>', 'IsolineOriginOptions$SideOfStreet' => '<p>Controls which side of the street is considered accessible from the origin point, particularly important for divided roads where building entrances or parking access may only be available from one direction.</p>', ], ], 'IsolineThresholds' => [ 'base' => '<p>Specifies the time or distance limits used to calculate reachable areas. You can provide up to five thresholds for a single type to generate multiple isolines in a single request. For example, you might request areas reachable within 5, 10, and 15 minutes, or within 1, 2, and 5 kilometers.</p>', 'refs' => [ 'CalculateIsolinesRequest$Thresholds' => '<p>The distance or time thresholds used to determine reachable areas. You can specify up to five thresholds (which all must be the same type) to calculate multiple isolines in a single request. For example, to determine the areas that are reachable within 10 and 20 minutes of the origin, specify time thresholds of 600 and 1200 seconds.</p> <p>You incur a calculation charge for each threshold. Using a large number of thresholds in a request can lead to unexpected charges. For more information, see <a href="https://docs.aws.amazon.com/location/latest/developerguide/routes-pricing.html">Routes pricing</a> in the <i>Amazon Location Service Developer Guide</i>.</p>', ], ], 'IsolineTrafficOptions' => [ 'base' => '<p>Controls how real-time and historical traffic data is used when calculating reachable areas. This affects both the size and shape of isolines by accounting for expected travel speeds based on congestion patterns.</p>', 'refs' => [ 'CalculateIsolinesRequest$Traffic' => '<p>Configures how real-time and historical traffic data affects isoline calculations. Traffic patterns can significantly impact reachable areas, especially during peak hours.</p>', ], ], 'IsolineTrailerOptions' => [ 'base' => '<p>Additional specifications when the vehicle includes one or more trailers.</p>', 'refs' => [ 'IsolineTruckOptions$Trailer' => '<p>Optional specifications for attached trailers. When provided, trailer characteristics affect route calculations to ensure compliance with trailer-specific restrictions such as length limits, weight distribution requirements, and access restrictions for multi-trailer configurations.</p>', ], ], 'IsolineTrailerOptionsAxleCountInteger' => [ 'base' => NULL, 'refs' => [ 'IsolineTrailerOptions$AxleCount' => '<p>The total number of axles across all trailers. Used for weight distribution calculations and road restrictions.</p>', ], ], 'IsolineTrailerOptionsTrailerCountInteger' => [ 'base' => NULL, 'refs' => [ 'IsolineTrailerOptions$TrailerCount' => '<p>The number of trailers being pulled. Affects which roads can be used based on local regulations.</p> <p>Default value: <code>0</code> </p>', ], ], 'IsolineTravelMode' => [ 'base' => NULL, 'refs' => [ 'CalculateIsolinesRequest$TravelMode' => '<p>The mode of transportation to use for calculations. This affects which road types or features can be used, estimated speed, and the traffic levels that are applied.</p> <ul> <li> <p> <code>Car</code>—Standard passenger vehicle routing using roads accessible to cars</p> </li> <li> <p> <code>Pedestrian</code>—Walking routes using pedestrian paths, sidewalks, and crossings</p> </li> <li> <p> <code>Scooter</code>—Light two-wheeled vehicle routing using roads and paths accessible to scooters</p> </li> <li> <p> <code>Truck</code>—Commercial truck routing considering vehicle dimensions, weight restrictions, and hazardous material regulations</p> </li> </ul> <note> <p>The mode <code>Scooter</code> also applies to motorcycles; set this to <code>Scooter</code> when calculating isolines for motorcycles.</p> </note> <p>Default value: <code>Car</code> </p>', ], ], 'IsolineTravelModeOptions' => [ 'base' => '<p>Mode-specific routing options that further refine how reachable areas are calculated. Options are only considered when they match the selected travel mode.</p>', 'refs' => [ 'CalculateIsolinesRequest$TravelModeOptions' => '<p>Additional attributes that refine how reachable areas are calculated based on specific vehicle characteristics. These options help produce more accurate results by accounting for real-world constraints and capabilities.</p> <p>For example:</p> <ul> <li> <p>For trucks (<code>Truck</code>), specify dimensions, weight limits, and hazardous cargo restrictions to ensure isolines only include roads that can physically and legally accommodate the vehicle</p> </li> <li> <p>For cars (<code>Car</code>), set maximum speed capabilities or indicate high-occupancy vehicle eligibility to better estimate reachable areas</p> </li> <li> <p>For scooters (<code>Scooter</code>), specify engine type and speed limitations to more accurately model their travel capabilities</p> </li> </ul> <p>Without these options, calculations use default assumptions that may not match your specific use case.</p>', ], ], 'IsolineTruckOptions' => [ 'base' => '<p>Vehicle characteristics and restrictions that affect which roads can be used when calculating reachable areas for trucks. These details ensure that routes respect physical limitations and legal requirements.</p> <p>These apply when the provided travel mode is <code>Truck</code> </p>', 'refs' => [ 'IsolineTravelModeOptions$Truck' => '<p>Options specific to commercial truck routing (<code>Truck</code>, including vehicle dimensions, weight limits, and hazardous cargo specifications.</p>', ], ], 'IsolineTruckOptionsAxleCountInteger' => [ 'base' => NULL, 'refs' => [ 'IsolineTruckOptions$AxleCount' => '<p>The total number of axles on the vehicle. Required for certain road restrictions and weight limit calculations.</p>', ], ], 'IsolineTruckOptionsHeightAboveFirstAxleLong' => [ 'base' => NULL, 'refs' => [ 'IsolineTruckOptions$HeightAboveFirstAxle' => '<p>The height in centimeters measured from the ground to the highest point above the first axle. Used for specific bridge and tunnel clearance restrictions.</p> <p> <b>Unit</b>: <code>centimeters</code> </p>', ], ], 'IsolineTruckOptionsHeightLong' => [ 'base' => NULL, 'refs' => [ 'IsolineTruckOptions$Height' => '<p>The vehicle height in centimeters. Used to avoid routes with low bridges or other height restrictions.</p> <p> <b>Unit</b>: <code>centimeters</code> </p>', ], ], 'IsolineTruckOptionsLengthLong' => [ 'base' => NULL, 'refs' => [ 'IsolineTruckOptions$Length' => '<p>The total vehicle length in centimeters. Used to avoid roads with length restrictions and determine if the vehicle can safely navigate turns.</p> <p> <b>Unit</b>: <code>centimeters</code> </p>', ], ], 'IsolineTruckOptionsMaxSpeedDouble' => [ 'base' => NULL, 'refs' => [ 'IsolineTruckOptions$MaxSpeed' => '<p>The maximum speed in kilometers per hour at which the vehicle can or is permitted to travel. This affects travel time calculations and may result in different reachable areas compared to using default speed limits. Value must be between 3.6 and 252 kilometers per hour.</p> <p> <b>Unit</b>: <code>kilometers per hour</code> </p>', ], ], 'IsolineTruckOptionsOccupancyInteger' => [ 'base' => NULL, 'refs' => [ 'IsolineTruckOptions$Occupancy' => '<p>The number of occupants in the vehicle. This can affect route calculations by enabling the use of high-occupancy vehicle (HOV) lanes where minimum occupancy requirements are met.</p> <p>Default value: <code>1</code> </p>', ], ], 'IsolineTruckOptionsTireCountInteger' => [ 'base' => NULL, 'refs' => [ 'IsolineTruckOptions$TireCount' => '<p>The total number of tires on the vehicle.</p>', ], ], 'IsolineTruckOptionsWidthLong' => [ 'base' => NULL, 'refs' => [ 'IsolineTruckOptions$Width' => '<p>The vehicle width in centimeters. Used to avoid routes with width restrictions.</p> <p> <b>Unit</b>: <code>centimeters</code> </p>', ], ], 'IsolineTruckType' => [ 'base' => NULL, 'refs' => [ 'IsolineTruckOptions$TruckType' => '<p>The type of truck: <code>LightTruck</code> for smaller delivery vehicles, <code> StraightTruck </code> for rigid body trucks, or <code>Tractor</code> for tractor-trailer combinations.</p>', ], ], 'IsolineVehicleLicensePlate' => [ 'base' => '<p>License plate information used in regions where road access or routing restrictions are based on license plate numbers.</p>', 'refs' => [ 'IsolineCarOptions$LicensePlate' => '<p>License plate information used in regions where road access or routing restrictions are based on license plate numbers.</p>', 'IsolineScooterOptions$LicensePlate' => '<p>License plate information used in regions where road access or routing restrictions are based on license plate numbers.</p>', 'IsolineTruckOptions$LicensePlate' => '<p>License plate information used in regions where road access or routing restrictions are based on license plate numbers.</p>', ], ], 'IsolineVehicleLicensePlateLastCharacterString' => [ 'base' => NULL, 'refs' => [ 'IsolineVehicleLicensePlate$LastCharacter' => '<p>The last character of the vehicle\'s license plate. Used to determine road access restrictions in regions with license plate-based traffic management systems.</p>', ], ], 'IsolineZoneCategory' => [ 'base' => NULL, 'refs' => [ 'IsolineAvoidanceZoneCategory$Category' => '<p>The type of regulated zone: <code>CongestionPricing</code> for toll zones based on traffic levels, <code>Environmental</code> for low-emission zones, or <code>Vignette</code> for areas requiring special permits or stickers.</p>', ], ], 'LanguageTag' => [ 'bas