, 'RouteVehicleNoticeDetail$Title' => '<p>The notice title.</p>', 'RouteVehiclePlace$Name' => '<p>The name of the place.</p>', 'RouteVehicleTravelStep$Instruction' => '<p>Brief description of the step in the requested language.</p> <note> <p>Only available when the TravelStepType is Default.</p> </note>', 'RouteZone$Name' => '<p>The name of the zone.</p>', 'WaypointOptimizationFailedConstraint$Reason' => '<p>Reason for the failed constraint.</p>', ], ], 'SideOfStreetMatchingStrategy' => [ 'base' => NULL, 'refs' => [ 'IsolineSideOfStreetOptions$UseWith' => '<p>Controls whether side-of-street matching is applied to any street (<code>AnyStreet</code>) or only to divided roads (<code>DividedStreetOnly</code>). This is important when the exact side of the street matters - for example, if a building entrance is only accessible from one side of a divided highway, or if a parking lot can only be entered from northbound lanes. Without correct side-of-street matching, travel time estimates may be inaccurate because they don\'t account for necessary U-turns or detours to reach the correct side.</p> <p>Default value: <code>DividedStreetOnly</code> </p>', 'RouteMatrixSideOfStreetOptions$UseWith' => '<p>Strategy that defines when the side of street position should be used. AnyStreet will always use the provided position.</p> <p>Default value: <code>DividedStreetOnly</code> </p>', 'RouteSideOfStreetOptions$UseWith' => '<p>Strategy that defines when the side of street position should be used.</p> <p>Default value: <code>DividedStreetOnly</code> </p>', 'WaypointOptimizationSideOfStreetOptions$UseWith' => '<p>Strategy that defines when the side of street position should be used. AnyStreet will always use the provided position.</p> <p>Default value: <code>DividedStreetOnly</code> </p>', ], ], 'SnapToRoadsRequest' => [ 'base' => NULL, 'refs' => [], ], 'SnapToRoadsRequestSnapRadiusLong' => [ 'base' => NULL, 'refs' => [ 'SnapToRoadsRequest$SnapRadius' => '<p>The radius around the provide