ateRoutesRequest$DepartureTime' => '<p>Time of departure from the origin.</p> <p>Time format:<code>YYYY-MM-DDThh:mm:ss.sssZ | YYYY-MM-DDThh:mm:ss.sss+hh:mm</code> </p> <p>Examples:</p> <p> <code>2020-04-22T17:57:24Z</code> </p> <p> <code>2020-04-22T17:57:24+02:00</code> </p>', 'OptimizeWaypointsRequest$DepartureTime' => '<p>Departure time from the waypoint.</p> <p>Time format:<code>YYYY-MM-DDThh:mm:ss.sssZ | YYYY-MM-DDThh:mm:ss.sss+hh:mm</code> </p> <p>Examples:</p> <p> <code>2020-04-22T17:57:24Z</code> </p> <p> <code>2020-04-22T17:57:24+02:00</code> </p>', 'RoadSnapTracePoint$Timestamp' => '<p>Timestamp of the event.</p>', 'RouteFerryArrival$Time' => '<p>The time.</p>', 'RouteFerryDeparture$Time' => '<p>The time.</p>', 'RoutePedestrianArrival$Time' => '<p>The time.</p>', 'RoutePedestrianDeparture$Time' => '<p>The time.</p>', 'RouteVehicleArrival$Time' => '<p>The time.</p>', 'RouteVehicleDeparture$Time' => '<p>The departure time.</p>', 'RouteVehicleIncident$EndTime' => '<p>End timestamp of the incident.</p>', 'RouteVehicleIncident$StartTime' => '<p>Start time of the incident.</p>', 'WaypointOptimizationDestinationOptions$AppointmentTime' => '<p>Appointment time at the destination.</p>', 'WaypointOptimizationOptimizedWaypoint$ArrivalTime' => '<p>Estimated time of arrival at the destination.</p> <p>Time format:<code>YYYY-MM-DDThh:mm:ss.sssZ | YYYY-MM-DDThh:mm:ss.sss+hh:mm</code> </p> <p>Examples:</p> <p> <code>2020-04-22T17:57:24Z</code> </p> <p> <code>2020-04-22T17:57:24+02:00</code> </p>', 'WaypointOptimizationOptimizedWaypoint$DepartureTime' => '<p>Estimated time of departure from the origin.</p> <p>Time format:<code>YYYY-MM-DDThh:mm:ss.sssZ | YYYY-MM-DDThh:mm:ss.sss+hh:mm</code> </p> <p>Examples:</p> <p> <code>2020-04-22T17:57:24Z</code> </p> <p> <code>2020-04-22T17:57:24+02:00</code> </p>', 'WaypointOptimizationWaypoint$AppointmentTime' => '<p>Appointment time at the waypoint.</p>', ], ], 'TrafficUsage' => [ 'base' => NULL, 'refs' => [ 'IsolineTrafficOptions$Usage' => '<p>Controls whether traffic data is used in calculations. <code>UseTrafficData</code> considers both real-time congestion and historical patterns, while <code>IgnoreTrafficData</code> calculates routes based solely on road types and speed limits. Using traffic data provides more accurate real-world estimates but may produce different results at different times of day.</p> <p>Default value: <code>UseTrafficData</code> </p>', 'RouteMatrixTrafficOptions$Usage' => '<p>Determines if traffic should be used or ignored while calculating the route.</p> <p>Default value: <code>UseTrafficData</code> </p>', 'RouteTrafficOptions$Usage' => '<p>Specifies how traffic data should be used when calculating routes.</p> <p>Default Value: <code>UseTrafficData</code> </p> <note> <p>Traffic data usage depends on the time parameters in your route request:</p> <ul> <li> <p>When <code>Usage</code> is set to <code>UseTrafficData</code>:</p> <ul> <li> <p>If <code>DepartNow</code> is set to <code>true</code>, or if you specify <code>DepartureTime</code> or <code>ArrivalTime</code>, then all traffic data is considered (including live traffic and closures).</p> </li> <li> <p>If <code>DepartNow</code>, <code>DepartureTime</code>, and <code>ArrivalTime</code> are all unspecified, then only long-term closures are considered, regardless of this setting.</p> </li> </ul> </li> <li> <p>When <code>Usage</code> is set to <code>IgnoreTrafficData</code>, then all traffic data is ignored regardless of the time parameters in your route request.</p> </li> </ul> </note>', 'WaypointOptimizationTrafficOptions$Usage' => '<p>Determines if traffic should be used or ignored while calculating the route.</p> <p>Default value: <code>UseTrafficData</code> </p>', ], ], 'TruckRoadType' => [ 'base' => NULL, 'refs' => [ 'TruckRoadTypeList$member' => NULL, ], ], 'TruckRoadTypeList' => [ 'base' => NULL, 'refs' => [ 'IsolineAvoidanceOptions$TruckRoadTypes' => '<p>For truck travel modes, indicates specific road classificat