>', ], ], 'WaypointOptimizationRestProfile' => [ 'base' => '<p>Pre defined rest profiles for a driver schedule. The only currently supported profile is EU.</p>', 'refs' => [ 'WaypointOptimizationDriverOptions$RestProfile' => '<p>Pre defined rest profiles for a driver schedule. The only currently supported profile is EU.</p>', ], ], 'WaypointOptimizationRestProfileProfileString' => [ 'base' => NULL, 'refs' => [ 'WaypointOptimizationRestProfile$Profile' => '<p>Pre defined rest profiles for a driver schedule. The only currently supported profile is EU.</p>', ], ], 'WaypointOptimizationSequencingObjective' => [ 'base' => NULL, 'refs' => [ 'OptimizeWaypointsRequest$OptimizeSequencingFor' => '<p>Specifies the optimization criteria for the calculated sequence.</p> <p>Default value: <code>FastestRoute</code>.</p>', ], ], 'WaypointOptimizationServiceTimeTreatment' => [ 'base' => NULL, 'refs' => [ 'WaypointOptimizationDriverOptions$TreatServiceTimeAs' => '<p>If the service time provided at a waypoint/destination should be considered as rest or work. This contributes to the total time breakdown returned within the response.</p>', ], ], 'WaypointOptimizationSideOfStreetOptions' => [ 'base' => '<p>Options to configure matching the provided position to a side of the street.</p>', 'refs' => [ 'WaypointOptimizationDestinationOptions$SideOfStreet' => '<p>Options to configure matching the provided position to a side of the street.</p>', 'WaypointOptimizationWaypoint$SideOfStreet' => '<p>Options to configure matching the provided position to a side of the street.</p>', ], ], 'WaypointOptimizationTimeBreakdown' => [ 'base' => '<p>Time breakdown for the sequence.</p>', 'refs' => [ 'OptimizeWaypointsResponse$TimeBreakdown' => '<p>Time breakdown for the sequence.</p>', ], ], 'WaypointOptimizationTrafficOptions' => [ 'base' => '<p>Options related to traffic.</p>', 'refs' => [ 'OptimizeWaypointsRequest$Traffic' => '<p>Traffic-related options.</p>', ], ], 'WaypointOptimizationTrailerOptions'